        vector<bool> visited(rooms.size(), false);
        dfs(rooms, 0, visited);
        for (bool b : visited) {
            if (!b) return false;
        }
        return true;
    }

    void dfs(vector<vector<int>>& rooms, int index, vector<bool>& visited) {
        visited[index] = true;
        for (int key : rooms[index]) {
            if (!visited[key]) {
                dfs(rooms, key, visited);
            }
        }
    }
};
